@* Displays a single task card with move buttons *@

<div class="task-card">
    <div class="task-card-header">
        <span class="task-title">@Task.Title</span>
        <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    </div>
    <div class="task-card-body">
        <span class="task-assignee">@Task.Assignee</span>
        <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>
    </div>
    <div class="task-card-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="() => OnMoveLeft.InvokeAsync(Task)">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="() => OnMoveRight.InvokeAsync(Task)">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }
}

@* Inline form to create a new task within a column *@

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" />
        <input type="text" placeholder="Assignee" @bind="assignee" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<NewTaskModel> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
            return;

        await OnTaskCreated.InvokeAsync(new NewTaskModel(title, assignee, priority, dueDate));
        IsVisible = false;
        ResetForm();
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);
}

@* A single Kanban column displaying its tasks and an add-task form *@

<div class="board-column">
    <div class="column-header">
        <h3>@ColumnName</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>
    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="OnMoveLeft"
                      OnMoveRight="OnMoveRight" />
        }
    </div>
    <div class="column-footer">
        <AddTaskForm OnTaskCreated="OnTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback<TaskItem> OnMoveRight { get; set; }

    [Parameter]
    public EventCallback<AddTaskForm.NewTaskModel> OnTaskCreated { get; set; }
}

@* Search bar for filtering tasks by title *@

<div class="board-search">
    <input type="text"
           placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter]
    public string SearchText { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<string> OnSearchChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await OnSearchChanged.InvokeAsync(value);
    }
}

@page "/board"
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="loading-message">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <p class="error-message">@errorMessage</p>
}
else
{
    <BoardStats Total="allTasks.Count"
                TodoCount="todoTasks.Count"
                InProgressCount="inProgressTasks.Count"
                DoneCount="doneTasks.Count"
                OverdueCount="overdueTasks.Count" />

    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="filteredTodo"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="model => CreateTask(model, \"To Do\")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="filteredInProgress"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, \"To Do\")"
                     OnMoveRight="task => MoveTask(task, \"Done\")"
                     OnTaskCreated="model => CreateTask(model, \"In Progress\")" />

        <BoardColumn ColumnName="Done"
                     Tasks="filteredDone"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, \"In Progress\")"
                     OnTaskCreated="model => CreateTask(model, \"Done\")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    private List<TaskItem> todoTasks => allTasks.Where(t => t.Status == "To Do").ToList();
    private List<TaskItem> inProgressTasks => allTasks.Where(t => t.Status == "In Progress").ToList();
    private List<TaskItem> doneTasks => allTasks.Where(t => t.Status == "Done").ToList();
    private int overdueCount => allTasks.Count(t => t.DueDate < DateTime.Today);
    private List<TaskItem> overdueTasks => allTasks.Where(t => t.DueDate < DateTime.Today).ToList();

    private List<TaskItem> filteredTodo => FilterBySearch(todoTasks);
    private List<TaskItem> filteredInProgress => FilterBySearch(inProgressTasks);
    private List<TaskItem> filteredDone => FilterBySearch(doneTasks);

    private List<TaskItem> FilterBySearch(List<TaskItem> tasks)
    {
        if (string.IsNullOrWhiteSpace(searchText))
            return tasks;
        return tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    protected override async Task OnInitializedAsync()
    {
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private void HandleSearchChanged(string value)
    {
        searchText = value;
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = allTasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                allTasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(AddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            allTasks.Add(newTask with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
        }
    }
}

